{
    Console.WriteLine($"=== Dataset has only {rowCount} rows — skipping train/test split ===");
    Console.WriteLine("  Add more data (≥20 rows) for reliable evaluation metrics.");
    trainData = rawData;
    trainSchema = rawData.Schema;
